import React, { useState } from 'react';

function SellerDash() {
  const [myItems, setMyItems] = useState([
    { id: 1, name: 'Wheat', location: 'Punjab', price: 500 }
  ]);

  return (
    <div style={{ padding: '20px' }}>
      <h2>Seller Dashboard</h2>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
        <div style={{ border: '1px solid #ccc', padding: '20px' }}>
          <h3>List New Product</h3>
          <input type="text" placeholder="Product Name" style={{ display: 'block', marginBottom: '10px' }} />
          <input type="number" placeholder="Price" style={{ display: 'block', marginBottom: '10px' }} />
          <button style={{ background: 'green', color: 'white' }}>Post Listing</button>
        </div>

        <div style={{ background: '#fff3e0', padding: '20px' }}>
          <h3>📈 AI Growth Graph</h3>
          <div style={{ height: '100px', background: '#ddd', display: 'flex', alignItems: 'flex-end', gap: '5px' }}>
            <div style={{ height: '40%', width: '20px', background: 'orange' }}></div>
            <div style={{ height: '60%', width: '20px', background: 'orange' }}></div>
            <div style={{ height: '90%', width: '20px', background: 'orange' }}></div>
          </div>
          <p>Your profits are up 20% this month!</p>
        </div>
      </div>
    </div>
  );
}

export default SellerDash;
